import{_ as e,o as i,c as r,ag as a}from"./chunks/framework.BbyMWZAR.js";const c=JSON.parse('{"title":"进程、线程、协程与 Web Worker","description":"","frontmatter":{"title":"进程、线程、协程与 Web Worker","difficulty":"medium","tags":["进程","线程","协程","WebWorker","worker_threads"],"estimate":20},"headers":[],"relativePath":"domains/browser/qa/qa-22-process-thread-webworker.md","filePath":"domains/browser/qa/qa-22-process-thread-webworker.md","lastUpdated":1783504823000}'),t={name:"domains/browser/qa/qa-22-process-thread-webworker.md"};function l(n,s,o,d,h,k){return i(),r("div",null,[...s[0]||(s[0]=[a(`<h1 id="问答-22-进阶-进程、线程、协程与-web-worker" tabindex="-1">问答 22（进阶）：进程、线程、协程与 Web Worker <a class="header-anchor" href="#问答-22-进阶-进程、线程、协程与-web-worker" aria-label="Permalink to &quot;问答 22（进阶）：进程、线程、协程与 Web Worker&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>进程、线程、协程分别是什么，有什么区别？浏览器里的 Web Worker 是什么？和 Node.js 的 <code>worker_threads</code> 相比呢？</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><strong>进程 vs 线程 vs 协程</strong></p><table tabindex="0"><thead><tr><th>维度</th><th>进程</th><th>线程</th><th>协程</th></tr></thead><tbody><tr><td>资源单位</td><td>OS 分配资源的基本单位</td><td>CPU 调度的基本单位</td><td>用户态调度，比线程更轻</td></tr><tr><td>内存</td><td>独立地址空间</td><td>共享进程地址空间</td><td>共享，栈可小到几 KB</td></tr><tr><td>通信</td><td>IPC（管道 / 共享内存 / socket / signal）</td><td>共享内存 + 锁</td><td>通过运行时机制（channel、await）</td></tr><tr><td>切换成本</td><td>高（切页表、TLB flush）</td><td>中（切寄存器）</td><td>极低（不涉及内核）</td></tr><tr><td>崩溃影响</td><td>只影响自己</td><td>会拖崩整个进程</td><td>只影响自己（协程）</td></tr><tr><td>例子</td><td>浏览器 tab 各自一个 renderer 进程</td><td>Java 线程池</td><td>Go goroutine、JS async / await、Python asyncio</td></tr></tbody></table><p><strong>要点</strong></p><ul><li><strong>进程</strong>：内核视角的资源容器，稳定隔离，开销大。</li><li><strong>线程</strong>：进程内的执行流，共享内存能高效协作但要处理竞态。</li><li><strong>协程</strong>：用户态调度的「更轻的线程」，切换靠函数让出（yield / await），不进内核，一台机器可跑百万协程。</li><li>现代 JS 里的 async / await 本质是协程语法糖：一个 async function 就是一段可暂停可恢复的执行流，靠事件循环调度。</li></ul><p><strong>Web Worker</strong></p><ul><li>浏览器提供的<strong>独立 JS 线程</strong>，与主线程通过 <code>postMessage</code> 通信。</li><li>目的：把 CPU 密集任务（图像处理、加密、大数据解析）移到后台线程，避免阻塞主线程和渲染。</li><li>不能访问 DOM / window / document，只能访问 <code>self</code>、<code>fetch</code>、<code>Blob</code>、<code>IndexedDB</code>、<code>WebSocket</code> 等。</li><li><strong>通信</strong>：<code>postMessage(data, [transfer])</code>，可传 Transferable Object（<code>ArrayBuffer</code>、<code>MessagePort</code>、<code>ImageBitmap</code>），零拷贝。</li><li>三类： <ul><li><strong>Dedicated Worker</strong>：一对一，最常用。</li><li><strong>Shared Worker</strong>：多个 tab 共享，通过 <code>port</code> 通信。</li><li><strong>Service Worker</strong>：常驻，充当网络代理。</li></ul></li><li>示例：</li></ul><div class="language-js vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// main.js</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> w</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> new</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Worker</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">new</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> URL</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;./worker.js&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">meta</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.url), { type: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;module&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> });</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">w.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">postMessage</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({ cmd: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;crunch&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, payload: bigArrayBuffer }, [bigArrayBuffer]);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">w.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">onmessage</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> console.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">log</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;done&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, e.data);</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// worker.js</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">self.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">onmessage</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ({ </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> result</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> compute</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(data.payload);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  self.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">postMessage</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(result);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">};</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p><strong>Node.js <code>worker_threads</code></strong></p><ul><li>Node 10+ 提供的线程能力，语义与 Web Worker 类似，API 略有不同。</li><li>主要 API：<code>Worker</code>、<code>parentPort</code>、<code>workerData</code>、<code>MessageChannel</code>、<code>isMainThread</code>。</li><li><strong>共享内存</strong>：<code>SharedArrayBuffer</code> + <code>Atomics</code>，可跨线程共享内存并做原子操作。</li><li>与 Node <code>cluster</code> 的区别： <ul><li><code>cluster</code>：多<strong>进程</strong>（fork），每个进程独立 V8 实例、独立 GC，通过 IPC 通信；适合利用多核跑 HTTP 服务。</li><li><code>worker_threads</code>：多<strong>线程</strong>（同进程内多 V8 Isolate），共享部分内存，通信更快；适合 CPU 密集任务。</li></ul></li><li>Node 里的注意点： <ul><li><code>require</code> 缓存是 per-thread，每个 worker 会重新加载模块。</li><li>网络 / 文件 I/O 都是异步不阻塞主线程，Worker 主要用于 <strong>CPU 密集</strong>。</li><li>启动开销：几十到几百 ms，长期任务复用一个 pool。</li></ul></li></ul><h2 id="追问-1-主线程和-worker-之间传输大对象怎么最省" tabindex="-1">追问 1：主线程和 Worker 之间传输大对象怎么最省？ <a class="header-anchor" href="#追问-1-主线程和-worker-之间传输大对象怎么最省" aria-label="Permalink to &quot;追问 1：主线程和 Worker 之间传输大对象怎么最省？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>深拷贝（默认 <code>postMessage</code>）</strong>：走「结构化克隆算法」，同类型的对象都会被完整拷贝，大对象几十 MB 会明显卡顿。</li><li><strong>Transferable Object</strong>：把某些「大块内存」的所有权直接<strong>转移</strong>给对方，原线程再访问会抛错，但成本几乎为 0： <ul><li><code>ArrayBuffer</code></li><li><code>MessagePort</code></li><li><code>ImageBitmap</code></li><li><code>OffscreenCanvas</code></li><li><code>ReadableStream</code> / <code>WritableStream</code> / <code>TransformStream</code></li></ul></li><li>用法：<code>postMessage(obj, [obj.buffer])</code>。</li><li><strong>SharedArrayBuffer</strong>：不用转移，两侧都能同时读写；需要 <code>Atomics</code> 做同步；页面需启用 COOP + COEP 才能用（跨源隔离）。</li><li>建议：视频 / 音频 / 大数组用 Transferable 或 SharedArrayBuffer；小型 JSON 结构化克隆足够。</li></ul><h2 id="追问-2-worker-里能做「同步-fetch」吗-为什么" tabindex="-1">追问 2：Worker 里能做「同步 fetch」吗？为什么？ <a class="header-anchor" href="#追问-2-worker-里能做「同步-fetch」吗-为什么" aria-label="Permalink to &quot;追问 2：Worker 里能做「同步 fetch」吗？为什么？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>曾经可以：Worker 里的 <code>XMLHttpRequest</code> 支持 <code>async: false</code>（同步 XHR）。但已被浏览器逐渐弃用 / 移除。</li><li><strong>不推荐</strong>：即使能同步等，也会阻塞该 Worker 的事件循环，失去并发意义。</li><li>推荐做法：Worker 里同样用 <code>fetch()</code> + <code>await</code>，其它任务在 Worker 内并发处理。</li><li>若要「主线程等 Worker 完成」：主线程可以用 <code>Atomics.wait</code> + <code>SharedArrayBuffer</code> 做同步阻塞等待（真的会锁主线程，除非在 Worker 里做）。这是极少数场景（如 SQLite in WASM 想在 Worker 里做同步文件读）。</li></ul><h2 id="追问-3-什么场景用-web-worker-什么场景用-service-worker-两者能配合吗" tabindex="-1">追问 3：什么场景用 Web Worker，什么场景用 Service Worker？两者能配合吗？ <a class="header-anchor" href="#追问-3-什么场景用-web-worker-什么场景用-service-worker-两者能配合吗" aria-label="Permalink to &quot;追问 3：什么场景用 Web Worker，什么场景用 Service Worker？两者能配合吗？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>Web Worker</strong>：跑一次性的 CPU 密集任务。生命周期与页面绑定，页面关闭就结束。适合： <ul><li>大量数据解析（大 CSV / 大 JSON）。</li><li>图像 / 视频处理、加密、AI 推理。</li><li>复杂算法（棋类 AI、模拟计算）。</li></ul></li><li><strong>Service Worker</strong>：作为网络代理，长期驻留（浏览器管生命周期）。适合： <ul><li>离线缓存（PWA）。</li><li>请求拦截 / 转换。</li><li>推送通知（Push API）。</li><li>后台同步（Background Sync）。</li></ul></li><li><strong>配合</strong>：Service Worker 处理网络请求时，可能需要重活（如加密 / 解压），可以在 SW 里 <code>new Worker()</code> 委派任务；也可以由 SW 主动通知所有客户端 <code>clients.matchAll().postMessage()</code> 触发页面里的 Worker。</li><li>现代 PWA 常见架构：主线程 UI → Web Worker 计算 → Service Worker 处理网络 / 缓存，各司其职。</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/engineer/handbook/domains/browser/RESOURCES">浏览器 &amp; 网络 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://developer.mozilla.org/en-US/docs/Web/API/Web_Workers_API" target="_blank" rel="noreferrer">MDN: Web Workers API</a>：Web Worker 线程模型与通信</li><li><a href="https://html.spec.whatwg.org/multipage/workers.html" target="_blank" rel="noreferrer">HTML Living Standard: Workers</a>：Worker 规范定义</li><li><a href="https://www.chromium.org/developers/design-documents/multi-process-architecture/" target="_blank" rel="noreferrer">Chromium: Multi-process Architecture</a>：浏览器进程/线程架构</li></ul>`,25)])])}const g=e(t,[["render",l]]);export{c as __pageData,g as default};
